import React, { useEffect, useState, useCallback } from 'react';
import { useTable, useSortBy, useGlobalFilter, usePagination } from 'react-table';
import EditPurchase from './EditPurchase.js';
import './PurchaseFunc.css';
import AddPurchase from './AddPurchase.js';

const PurchaseFunc = ({ apiBaseUrl }) => {
  const [purchases, setPurchases] = useState([]);
  const [editingPurchase, setEditingPurchase] = useState(null);
  const [locations, setLocations] = useState([]);
  const [materials, setMaterials] = useState([]);
  const [vendors, setVendors] = useState([]);
  const [materialchanges, setMaterialchanges] = useState([]);
  const [error, setError] = useState(null);
  const [isLoading, setIsLoading] = useState(true);

  // Function to fetch data from the API
  const fetchData = useCallback(async () => {
    const authTokenCookie = document.cookie.split('; ').find((row) => row.startsWith('authToken='));

    if (authTokenCookie) {
      const token = authTokenCookie.split('=')[1];
      // Fetch data with authentication token
      const fetchAPI = async (url) => {
        const response = await fetch(url, {
          headers: {
            'Authorization': `Bearer ${token}`,
          },
        });

        if (!response.ok) {
          throw new Error(`Error fetching ${url}`);
        }
        return response.json();
      };

      try {
        // Fetch purchase data
        const purchaseData = await fetchAPI(`${apiBaseUrl}/PurchasesAPI`);
        setPurchases(purchaseData);
      } catch (error) {
        console.log('Error fetching purchases:', error);
        setError(error.message);
      }

      // Fetch other data (locations, materials, vendors, material changes, etc.)
      try {
        const locationData = await fetchAPI(`${apiBaseUrl}/LocationsAPI`);
        setLocations(locationData);
      } catch (error) {
        console.log('Error fetching locations:', error);
        setError(error.message);
      }

      try {
        const materialData = await fetchAPI(`${apiBaseUrl}/materiallist`);
        setMaterials(materialData);
      } catch (error) {
        console.log('Error fetching materials:', error);
        setError(error.message);
      }

      try {
        const vendorData = await fetchAPI(`${apiBaseUrl}/vendors`);
        setVendors(vendorData);
      } catch (error) {
        console.log('Error fetching vendors:', error);
        setError(error.message);
      }

      try {
        const materialchangesData = await fetchAPI(`${apiBaseUrl}/materialchangesAPI`);
        setMaterialchanges(materialchangesData);
      } catch (error) {
        console.log('Error fetching material changes:', error);
        setError(error.message);
      }
    }

    setIsLoading(false);
  }, [apiBaseUrl]);

  // useEffect to fetch data when the component mounts
  useEffect(() => {
    fetchData();
  }, [fetchData]);

  // ... (rest of the code for handling add, edit, delete, and rendering the table)

  return (
    <div>
      {/* AddPurchase component */}
      <AddPurchase
        handleAdd={handleAdd}
        locations={locations}
        vendors={vendors}
        setVendors={setVendors}
        materials={materials}
        setMaterials={setMaterials}
        apiBaseUrl={apiBaseUrl}
      />

      <div className="search">
        <input
          type="text"
          value={globalFilter || ''}
          onChange={(e) => setGlobalFilter(e.target.value)}
          placeholder="Search..."
        />
      </div>
      <table {...getTableProps()} className="purchase-table">
        {/* Table header */}
        <thead>
          {headerGroups.map((headerGroup) => (
            <tr {...headerGroup.getHeaderGroupProps()}>
              {headerGroup.headers.map((column) => (
                <th {...column.getHeaderProps(column.getSortByToggleProps())}>
                  {column.render('Header')}
                  <span>{column.isSorted ? (column.isSortedDesc ? ' 🔽' : ' 🔼') : ''}</span>
                </th>
              ))}
            </tr>
          ))}
        </thead>
        {/* Table body */}
        <tbody {...getTableBodyProps()}>
          {page.map((row) => {
            prepareRow(row);
            return (
              <React.Fragment key={row.getRowProps().key}>
                <tr {...row.getRowProps()}>
                  {row.cells.map((cell) => (
                    <td {...cell.getCellProps()}>{cell.render('Cell')}</td>
                  ))}
                </tr>
                {/* EditPurchase component */}
                {editingPurchase && editingPurchase.id === row.original.id && (
                  <tr>
                    <td colSpan={columns.length}>
                      <EditPurchase
                        purchase={editingPurchase}
                        handleUpdate={handleUpdate}
                        vendors={vendors}
                        locations={locations}
                        materials={materials}
                        purchases={purchases}
                        setPurchases={setPurchases}
                        handleCancel={handleCancel}
                        apiBaseUrl={apiBaseUrl}
                      />
                    </td>
                  </tr>
                )}
              </React.Fragment>
            );
          })}
        </tbody>
      </table>
      <div>
        {/* Pagination */}
        <button onClick={() => previousPage()} disabled={!canPreviousPage}>
          Previous
        </button>
        <button onClick={() => nextPage()} disabled={!canNextPage}>
          Next
        </button>
        <span>
          Page{' '}
          <strong>
            {pageIndex + 1} of {Math.ceil(purchases.length / pageSize)}
          </strong>{' '}
        </span>
        <span>
          | Go to page:{' '}
          <input
            type="number"
            defaultValue={pageIndex + 1}
            onChange={(e) => {
              const page = e.target.value ? Number(e.target.value) - 1 : 0;
              gotoPage(page);
            }}
            style={{ width: '50px' }}
          />
        </span>
        {/* Rows per page */}
        <select
          value={pageSize}
          onChange={(e) => {
            setPageSize(Number(e.target.value));
          }}
        >
          {[10, 25, 50].map((pageSize) => (
            <option key={pageSize} value={pageSize}>
              Show {pageSize}
            </option>
          ))}
        </select>
      </div>
    </div>
  );
};

export default PurchaseFunc;
